script:
frappe.ui.form.on('Asset', {
    refresh: function(frm) {
        // Show custom reason field only if status is 'Scrapped'
        frm.toggle_display('custom_reason_for_scrapping', frm.doc.status === 'Scrapped');

        // Only show custom Scrap Asset button if doc is submitted and status allows scrapping
        if (
            frm.doc.docstatus === 1 &&
            ["Submitted", "Partially Depreciated", "Fully Depreciated"].includes(frm.doc.status)
        ) {
            // Remove the default Scrap Asset button under Manage menu
            frm.remove_custom_button(__('Scrap Asset'), __('Manage'));

            // Add your custom Scrap Asset button under Manage menu
            frm.add_custom_button(__('Scrap Asset'), () => {
                if (!frm.doc.name || frm.is_new()) {
                    frappe.msgprint(__('Please save and submit the Asset before scrapping.'));
                    return;
                }
                show_scrap_dialog(frm);
            }, __('Manage'));
        }
    }
});

function show_scrap_dialog(frm) {
    let dialog = new frappe.ui.Dialog({
        title: __('Scrap Asset: {0}', [frm.doc.name]),
        fields: [
            {
                fieldtype: 'Small Text',
                fieldname: 'scrapping_reason',
                label: __('Reason for Scrapping'),
                reqd: 1,
                description: __('Please provide a reason for scrapping this asset')
            },
            {
                fieldtype: 'Date',
                fieldname: 'disposal_date',
                label: __('Disposal Date'),
                default: frappe.datetime.get_today(),
                reqd: 1
            }
        ],
        primary_action_label: __('Scrap Asset'),
        primary_action: function(values) {
            if (!values.scrapping_reason.trim()) {
                frappe.msgprint(__('Reason for scrapping is required.'));
                return;
            }

            // Call backend scrap method with required argument
            frappe.call({
                method: "erpnext.assets.doctype.asset.depreciation.scrap_asset",
                args: {
                    asset_name: frm.doc.name
                },
                callback: function(r) {
                    // After scrapping, update custom fields reason and disposal date
                    frappe.call({
                        method: 'frappe.client.set_value',
                        args: {
                            doctype: 'Asset',
                            name: frm.doc.name,
                            fieldname: {
                                custom_reason_for_scrapping: values.scrapping_reason,
                                disposal_date: values.disposal_date
                            }
                        },
                        callback: function() {
                            frappe.msgprint(__('Asset has been scrapped successfully.'));
                            frm.reload_doc();
                        }
                    });
                },
                error: function(err) {
                    frappe.msgprint(__('An error occurred while scrapping the asset.'));
                    console.error('Error scrapping asset:', err);
                }
            });

            dialog.hide();
        }
    });

    dialog.show();
}
